SET @DATACASH = 'EXEC MASTER.DBO.XP_CMDSHELL ''BCP " SELECT DATAFILE FROM ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG ORDER BY SRNO ASC  " QUERYOUT ' + @CASHFILENAME+ ' -c -t"," -c -t"," -r"\n" -T'', NO_OUTPUT'    
  
EXEC(@DATACASH)    
  
  
TRUNCATE TABLE ACCOUNT.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG  
TRUNCATE TABLE CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE

INSERT INTO MSAJAG.DBO.CLIENT_COLLATERAL_REPORTING_DETAILS_ANG_NSE  SELECT FILENAME,  
Date,  
CLEARING_PAN,TRADING_PAN,CP_CODE,CP_PAN,  
CLIENT_PAN,  
ACCOUNT_TYPE,SEGMENT_INDICATOR,--MTOM=PARTY_CODE,  
MTOM,  
