PROVED_COMM_RET_CM)+ ',' +CONVERT(VARCHAR(1000),OTHER_COLL_RET_CM)+ ',' +CONVERT(VARCHAR(1000),CASH_WNCL)+ ',' +CONVERT(VARCHAR(1000),BG_WNCL)+ ',' +CONVERT(VARCHAR(1000),FD_WNCL)+ ',' +CONVERT(VARCHAR(1000),  APPROVED_SEC_CASH_WNCL)+ ',' +CONVERT(VARCHAR(1000),APPROVED_SEC_NONCASH_WNCL)+ ',' +CONVERT(VARCHAR(1000),CC_APPROVED_COMM_WNCL)  
